+    let host = url
+        .strip_prefix("https://")
+        .or_else(|| url.strip_prefix("http://"))
+        .and_then(|rest| rest.split('/').next())
+        .unwrap_or(url);
+
+    host.ends_with(".salesforce.com")
+        || host.ends_with(".force.com")
+        || host == "salesforce.com"
+        || host == "force.com"
+}
